            ></el-input>
          </el-form-item>
          <el-form-item style="margin-top: 10px;width:300px;">
             <span class="ml-3 w-35 text-gray-600 inline-flex items-center"
             >打开数量</span
             ><el-input
                placeholder="打开个数"
                type="text"
                v-model="linkValue.runNum"
            ></el-input>
          </el-form-item>
