<script>
import JsonViewer from 'vue3-json-viewer'
import Clipboard from 'clipboard'
import Textarea from './textarea'
import list from '../utils/base/list'
import base from '../utils/base'

export default {
  name: 'OpenLink',
  props : {
    shellShowResult : {
      type : String
    },
  },
  components: {
    Textarea,
    JsonViewer,
    Clipboard,
  },
  data() {
    return {
      exampleList: [
        {Name : '%rand%' , Desc : '随机给与不重复的值' , 'Key' : 1},
      ],
      starList : [

      ],
      linkValue : {
        link : '',
        name : '',
        runNum : 1,
        isStar : 0,
      },
      runList : [],
    }
  },
  filters: {

  },
  mounted: function () {
    let _that = this
    base.PageInit(_that.name,
        function (boolInit) {

        }, function (boolInit) {
          _that.initStarList()
        })
  },
  methods: {
    showStarInfo : function (value) {
      let _that = this
      _that.linkValue = {...value}
    },
    runOpen : function () {
      let timestampInSeconds = Math.floor(Date.now() / 1000);
      for(let i = 0 ;i < this.linkValue.runNum ; i++){
        let link = this.linkValue.link.replace('%rand%' , timestampInSeconds + '' + i)
        window.open(link, '_blank');
      }
    },
    star : function (){
      let _that = this
      if(_that.linkValue.name === '' || _that.linkValue.link === ''){
        _that.$helperNotify.error('名称和链接不能为空')
        return
      }
      list.updateSetValue(_that.starList , 'name' , _that.linkValue)
      _that.$helperStore.setStore('starList' , JSON.stringify(_that.starList))
      _that.$helperNotify.success('收藏成功')
    },
    cancelStar : function (){
      let _that = this
      if(_that.linkValue.name === ''){
        _that.$helperNotify.error('名称不能为空')
        return
      }
      let retainStarList = []
      for(let key in _that.starList){
        if(_that.starList[key].name !== _that.linkValue.name){
          retainStarList.push(_that.starList[key])
        }
      }
      _that.starList = retainStarList
      _that.$helperStore.setStore('starList' , JSON.stringify(retainStarList))
      _that.$helperNotify.success('取消收藏成功')
    },
    initStarList : function (){
      let openLinkCache = this.$helperStore.getStore('starList')
      if (openLinkCache === '' || openLinkCache === null) {
        this.starList = [];
      }else{
        this.starList = JSON.parse(openLinkCache)
        if(this.starList.length > 0){
          this.linkValue = {...this.starList[0]}
        }
      }
    },
  },
}
</script>
